oxy_webhelp_navlinks = {"aws_permission_categories-d30753e13033":{"topics":[{"title":"Permission model and privilege elevation for AWS","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides a least permission model for AWS cloud accounts,         granting minimal necessary permissions, starting with read-only access. You can add the             <code class=\"ph codeph\">Basic<\/code> permission category initially and elevate permissions for         recovery operations when required.<\/p>","href":"saas\/aws_perm_model_privilege_elevation.html","attributes":{"data-id":"aws_perm_model_privilege_elevation"},"menu":{"hasChildren":false},"tocID":"aws_perm_model_privilege_elevation-d30753e13046","topics":[]},{"title":"Permissions boundary for cloud-native workloads protection","shortdesc":"<p class=\"shortdesc\">An AWS IAM permissions boundary defines the maximum permissions available to an <span class=\"ph\">RSC<\/span> role. Configuring the boundary with explicit <code class=\"ph codeph\">Allow<\/code>         statements for all required <span class=\"ph\">RSC<\/span> permissions prevents common allowlist         misconfiguration that can break cloud-native workload protection.<\/p>","href":"saas\/aws_cnp_permission_boundary.html","attributes":{"data-id":"aws_cnp_permission_boundary"},"menu":{"hasChildren":false},"tocID":"aws_cnp_permission_boundary-d30753e13062","topics":[]},{"title":"Managing granular permissions for an AWS cloud account","shortdesc":"<p class=\"shortdesc\">You can manage the permission categories for an AWS cloud account that you have         already added to <span class=\"ph\">RSC<\/span> by including or excluding permission categories, as         required.<\/p>","href":"saas\/aws_managing_granular_perms_cloud_acc.html","attributes":{"data-id":"aws_managing_granular_perms_cloud_acc"},"menu":{"hasChildren":false},"tocID":"aws_managing_granular_perms_cloud_acc-d30753e13082","topics":[]}]}};